                        @enderror\n                    </div>\n\n                    <div>\n                        <label for=\"link\" class=\"block text-sm font-medium text-gray-700 mb-2\">\n                            Enlace *\n                        </label>\n                        <input type=\"url\" name=\"link\" id=\"link\" value=\"{{ old('link') }}\" class=\"w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent\">\n                        @error('link')\n                            <p class=\"mt-1 text-sm text-red-600\">{{ $message }}</p>\n                        @enderror\n                    </div>\n\n                    <div>\n                        <label for=\"image\" class=\"block text-sm font-medium text-gray-700 mb-2\">\n                            Imagen\n                        </label>\n                        <input type=\"file\" name=\"image\" id=\"image\" accept=\"image/*\" class=\"w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent\">\n                        <p class=\"mt-1 text-xs text-gray-500\">Formatos permitidos: JPG, PNG, GIF. Tamaño máximo: 2MB</p>\n                        @error('image')\n                            <p class=\"mt-1 text-sm text-red-600\">{{ $message }}</p>\n                        @enderror\n                    </div>\n                </div>\n\n                {{-- Campos para Documentos --}}\n                <div id=\"document-fields\" class=\"hidden space-y-6\">\n                    <div>\n                        <label for=\"path\" class=\"block text-sm font-medium text-gray-700 mb-2\">\n                            Archivo *\n                        </label>\n                        <input type=\"file\" name=\"path\" id=\"path\" class=\"w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent\">\n                        <p class=\"mt-1 text-xs text-gray-500\">Formatos permitidos: PDF, DOC, DOCX, XLS, XLSX, PPT, PPTX. Tamaño máximo: 10MB</p>\n                        @error('path')\n                            <p class=\"mt-1 text-sm text-red-600\">{{ $message }}</p>\n                        @enderror\n                    </div>\n                </div>\n\n                {{-- Estado --}}\n                <div class=\"mb-6\">\n                    <label for=\"status\" class=\"block text-sm font-medium text-gray-700 mb-2\">\n                        Estado *\n                    </label>\n                    <select name=\"status\" id=\"status\" class=\"w-full border border-gray-300 rounded-lg px-3 py-2 focus:ring-2 focus:ring-blue-500 focus:border-transparent\" required>\n                        <option value=\"1\" {{ old('status', '1') == '1' ? 'selected' : '' }}>Activo</option>\n                        <option value=\"0\" {{ old('status') == '0' ? 'selected' : '' }}>Inactivo</option>\n                    </select>\n                    @error('status')\n                        <p class=\"mt-1 text-sm text-red-600\">{{ $message }}</p>\n                    @enderror\n                </div>\n\n                {{-- Botones --}}\n                <div class=\"flex justify-end gap-4 pt-6 border-t border-gray-200\">\n                    <a href=\"{{ route('admin.resources.index') }}\" class=\"btn px-6 py-2 border border-gray-300 rounded-lg text-gray-700 hover:bg-gray-50 transition\">\n                        Cancelar\n                    </a>\n                    <button type=\"submit\" class=\"btn px-6 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700 transition\">\n                        Crear Recurso\n                    </button>\n                </div>\n            </form>\n        </div>\n    </div>\n</div>\n\n<script>\ndocument.addEventListener('DOMContentLoaded', function() {\n    const typeSelect = document.getElementById('type_resource_id');\n    const blogFields = document.getElementById('blog-fields');\n    const documentFields = document.getElementById('document-fields');\n    \n    // Elementos de campos requeridos\n    const descriptionField = document.getElementById('description');\n    const linkField = document.getElementById('link');\n    const pathField = document.getElementById('path');\n    \n    function toggleFields() {\n        const selectedValue = typeSelect.value;\n        \n        // Ocultar todos los campos primero\n        blogFields.classList.add('hidden');\n        documentFields.classList.add('hidden');\n        \n        // Remover required de todos los campos\n        descriptionField.removeAttribute('required');\n        linkField.removeAttribute('required');\n        pathField.removeAttribute('required');\n        \n        // Mostrar campos según selección\n        if (selectedValue === 'blog') {\n            blogFields.classList.remove('hidden');\n            descriptionField.setAttribute('required', 'required');\n            linkField.setAttribute('required', 'required');\n        } else if (selectedValue && selectedValue !== 'blog') {\n            documentFields.classList.remove('hidden');\n            pathField.setAttribute('required', 'required');\n        }\n    }\n    \n    // Ejecutar al cargar la página para mantener estado\n    toggleFields();\n    \n    // Ejecutar al cambiar selección\n    typeSelect.addEventListener('change', toggleFields);\n});\n</script>\n@endsection